import React, { useState, useRef, useEffect } from 'react';
import { Source, ChatMessage, Theme } from '../types';
import { askGeminiPro } from '../services/geminiService';
import { GenerateContentResponse } from '@google/genai';
import MarkdownRenderer from './MarkdownRenderer';

interface ChatPanelProps {
  selectedSource: Source | null;
  isAuthenticated: boolean;
  theme: Theme;
}

export default function ChatPanel({ selectedSource, isAuthenticated, theme }: ChatPanelProps) {
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [useThinking, setUseThinking] = useState(false);
  const [attachedImage, setAttachedImage] = useState<{ data: string, mime: string } | null>(null);
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(scrollToBottom, [messages]);

  useEffect(() => {
    if (selectedSource) {
      setMessages([
        { sender: 'ai', text: `StudyLM Pro is ready. Analyzing "${selectedSource.name}". How can I help?` }
      ]);
    } else {
       setMessages([
        { sender: 'ai', text: isAuthenticated ? 'Select a source or upload an image to start a deep study session.' : 'Select a sample source to explore StudyLM Pro.' }
      ]);
    }
  }, [selectedSource, isAuthenticated]);

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (ev) => {
        setAttachedImage({
          data: ev.target?.result as string,
          mime: file.type
        });
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSendMessage = async (e: React.FormEvent) => {
    e.preventDefault();
    if ((!input.trim() && !attachedImage) || isLoading) return;

    const userMessage: ChatMessage = { 
        sender: 'user', 
        text: input || (attachedImage ? "Analyze this image." : ""),
        imageData: attachedImage?.data,
        mimeType: attachedImage?.mime,
        isThinking: useThinking
    };

    const newHistory = [...messages, userMessage];
    setMessages(newHistory);
    setInput('');
    setAttachedImage(null);
    setIsLoading(true);

    try {
      const stream = await askGeminiPro(newHistory, useThinking, selectedSource?.content);
      let aiResponse = '';
      setMessages(prev => [...prev, { sender: 'ai', text: '', isThinking: useThinking }]);

      for await (const chunk of stream) {
        const c = chunk as GenerateContentResponse;
        aiResponse += c.text;
        setMessages(prev => {
          const updated = [...prev];
          updated[updated.length - 1].text = aiResponse;
          return updated;
        });
      }
    } catch (error) {
      console.error("Chat error:", error);
      setMessages(prev => [...prev, { sender: 'ai', text: "Gemini encountered an issue. Please try again." }]);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="flex flex-col h-full p-4 relative">
      <div className={`flex items-center justify-between mb-4 border-b pb-2 transition-colors duration-300 ${theme === 'oled' ? 'border-gray-800' : 'border-gray-200 dark:border-gray-700'}`}>
        <h2 className="text-lg font-bold text-gray-900 dark:text-white flex items-center">
            <svg className="w-5 h-5 mr-2 text-indigo-500" fill="currentColor" viewBox="0 0 20 20"><path d="M2 5a2 2 0 012-2h7a2 2 0 012 2v4a2 2 0 01-2 2H9l-3 3v-3H4a2 2 0 01-2-2V5z"></path></svg>
            StudyLM Pro
        </h2>
        <button 
            onClick={() => setUseThinking(!useThinking)}
            className={`flex items-center space-x-2 px-3 py-1 rounded-full text-xs font-bold transition-all duration-300 border ${
                useThinking 
                ? 'bg-indigo-600 text-white border-indigo-400 shadow-md animate-pulse' 
                : `${theme === 'oled' ? 'bg-gray-800' : 'bg-gray-100 dark:bg-gray-700'} text-gray-500 dark:text-gray-400 border-transparent hover:border-gray-300 dark:hover:border-gray-600`
            }`}
            title="Enable Gemini Thinking Mode for complex reasoning"
        >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9.663 17h4.673M12 3v1m6.364 1.636l-.707.707M21 12h-1M4 12H3m3.343-5.657l-.707-.707m2.828 9.9a5 5 0 117.072 0l-.548.547A3.374 3.374 0 0014 18.469V19a2 2 0 11-4 0v-.531c0-.895-.356-1.754-.988-2.386l-.548-.547z" /></svg>
            <span>DEEP THINK</span>
        </button>
      </div>

      <div className="flex-grow overflow-y-auto mb-4 pr-2 space-y-4">
        {messages.map((msg, index) => (
          <div key={index} className={`flex ${msg.sender === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[85%] px-4 py-3 rounded-2xl shadow-sm ${
                msg.sender === 'user' 
                ? 'bg-indigo-600 text-white' 
                : `${theme === 'oled' ? 'bg-gray-800' : 'bg-gray-100 dark:bg-gray-700'} text-gray-800 dark:text-gray-200`
            }`}>
              {msg.imageData && (
                  <div className="mb-2 rounded-lg overflow-hidden border border-white/20">
                      <img src={msg.imageData} alt="Uploaded for analysis" className="w-full h-auto max-h-48 object-cover" />
                  </div>
              )}
              {msg.isThinking && msg.sender === 'ai' && !msg.text && (
                  <div className="flex items-center text-xs text-indigo-500 dark:text-indigo-400 font-bold mb-1">
                      <svg className="w-3 h-3 mr-1 animate-spin" fill="none" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg>
                      Thinking deeply...
                  </div>
              )}
              <div className="prose prose-sm dark:prose-invert">
                <MarkdownRenderer content={msg.text} />
              </div>
            </div>
          </div>
        ))}
        {isLoading && messages[messages.length-1].sender === 'user' && (
            <div className="flex justify-start">
                <div className={`${theme === 'oled' ? 'bg-gray-800' : 'bg-gray-100 dark:bg-gray-700'} px-4 py-2 rounded-2xl shadow-sm`}>
                    <div className="flex items-center space-x-2">
                        <div className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce"></div>
                        <div className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce delay-75"></div>
                        <div className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce delay-150"></div>
                    </div>
                </div>
            </div>
        )}
        <div ref={messagesEndRef} />
      </div>

      <div className="relative">
          {attachedImage && (
              <div className={`absolute bottom-full left-0 mb-2 p-2 border rounded-lg shadow-xl flex items-center group transition-colors duration-300 ${theme === 'oled' ? 'bg-black border-gray-800' : 'bg-white dark:bg-gray-800 border-gray-200 dark:border-gray-700'}`}>
                  <img src={attachedImage.data} className="w-12 h-12 rounded object-cover" />
                  <button 
                    onClick={() => setAttachedImage(null)}
                    className="ml-2 p-1 text-red-500 hover:bg-red-50 dark:hover:bg-red-900/20 rounded"
                  >
                      <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
                  </button>
              </div>
          )}
          <form onSubmit={handleSendMessage} className={`flex items-center rounded-2xl p-1 shadow-inner border focus-within:border-indigo-500 transition-all ${theme === 'oled' ? 'bg-gray-800 border-gray-700' : 'bg-gray-100 dark:bg-gray-700 border-transparent'}`}>
            <input type="file" ref={fileInputRef} onChange={handleImageUpload} accept="image/*" className="hidden" />
            <button 
                type="button" 
                onClick={() => fileInputRef.current?.click()}
                className="p-3 text-gray-500 hover:text-indigo-500 dark:text-gray-400 dark:hover:text-indigo-300 transition-colors"
                title="Upload image for AI analysis"
            >
                <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" /></svg>
            </button>
            <input
              type="text"
              value={input}
              onChange={(e) => setInput(e.target.value)}
              placeholder={isLoading ? "Gemini is thinking..." : "Ask StudyLM anything..."}
              disabled={isLoading}
              className="flex-grow bg-transparent text-gray-900 dark:text-white p-3 focus:outline-none text-sm placeholder:text-gray-400"
            />
            <button type="submit" disabled={(!input.trim() && !attachedImage) || isLoading} className="bg-indigo-600 text-white p-3 rounded-xl hover:bg-indigo-700 disabled:bg-gray-400 dark:disabled:bg-gray-600 shadow-lg active:scale-95 transition-all">
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 10l7-7m0 0l7 7m-7-7v18" /></svg>
            </button>
          </form>
      </div>
    </div>
  );
}

import React, { useState, useRef, useEffect } from 'react';
import { SearchMessage, TrustedSource, ExamBoard, UserTier, Theme } from '../types';
import MarkdownRenderer from './MarkdownRenderer';

interface AiSearchProps {
  onSearch: (query: string, trustedSources: TrustedSource[], examBoards: ExamBoard[]) => void;
  searchHistory: SearchMessage[];
  isLoading: boolean;
  userTier: UserTier;
  searchCount: number;
  maxSearches: number;
  theme: Theme;
}

const sourceOptions: TrustedSource[] = ['Britannica', 'Khan Academy', 'Wikipedia'];
const examBoardOptions: ExamBoard[] = ['AQA', 'OCR', 'Edexcel'];

export default function AiSearch({ onSearch, searchHistory, isLoading, userTier, searchCount, maxSearches, theme }: AiSearchProps) {
  const [query, setQuery] = useState('');
  const [selectedSources, setSelectedSources] = useState<TrustedSource[]>([]);
  const [selectedExamBoards, setSelectedExamBoards] = useState<ExamBoard[]>([]);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [searchHistory, isLoading]);

  const handleSourceToggle = (source: TrustedSource) => {
    setSelectedSources(prev => 
      prev.includes(source) 
        ? prev.filter(s => s !== source)
        : [...prev, source]
    );
  };

  const handleExamBoardToggle = (board: ExamBoard) => {
    setSelectedExamBoards(prev =>
      prev.includes(board)
        ? prev.filter(b => b !== board)
        : [...prev, board]
    );
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (query.trim() && !isLoading) {
      onSearch(query.trim(), selectedSources, selectedExamBoards);
      setQuery('');
    }
  };

  const remaining = Math.max(0, maxSearches - searchCount);
  const isLimited = userTier === 'free';

  return (
    <div className="flex flex-col h-full w-full max-w-4xl mx-auto">
      <div className={`pt-2 pb-4 border-b transition-colors duration-300 ${theme === 'oled' ? 'border-gray-800' : 'border-gray-200 dark:border-gray-700'}`}>
        <div className="flex flex-col items-center">
            <h2 className="text-2xl font-bold text-gray-900 dark:text-white text-center">Search with Gemini</h2>
            {isLimited && (
                <div className={`mt-2 flex items-center px-3 py-1 rounded-full transition-colors duration-300 ${theme === 'oled' ? 'bg-indigo-900/50' : 'bg-indigo-50 dark:bg-indigo-900/30'}`}>
                    <div className="w-2 h-2 bg-indigo-500 rounded-full mr-2"></div>
                    <span className="text-xs font-semibold text-indigo-600 dark:text-indigo-300">
                        {remaining} free searches remaining today
                    </span>
                </div>
            )}
        </div>
        <div className="mt-4 flex flex-col lg:flex-row items-center justify-center gap-4">
            <div className="flex items-center gap-2">
              <span className="text-xs font-bold text-gray-400 uppercase tracking-tighter">Sources:</span>
              <div className="flex gap-1">
                {sourceOptions.map(source => (
                    <button
                    key={source}
                    type="button"
                    onClick={() => handleSourceToggle(source)}
                    className={`px-3 py-1 text-xs rounded-full transition-all duration-200 ${
                        selectedSources.includes(source)
                        ? 'bg-indigo-600 text-white shadow-md'
                        : `${theme === 'oled' ? 'bg-gray-800 border border-gray-700 hover:bg-gray-700' : 'bg-gray-200 dark:bg-gray-700 hover:bg-gray-300 dark:hover:bg-gray-600'} text-gray-600 dark:text-gray-300`
                    }`}
                    >
                    {source}
                    </button>
                ))}
              </div>
            </div>
            <div className="hidden lg:block w-px h-4 bg-gray-300 dark:bg-gray-600"></div>
            <div className="flex items-center gap-2">
               <span className="text-xs font-bold text-gray-400 uppercase tracking-tighter">Boards:</span>
               <div className="flex gap-1">
                {examBoardOptions.map(board => (
                    <button
                    key={board}
                    type="button"
                    onClick={() => handleExamBoardToggle(board)}
                    className={`px-3 py-1 text-xs rounded-full transition-all duration-200 ${
                        selectedExamBoards.includes(board)
                        ? 'bg-indigo-600 text-white shadow-md'
                        : `${theme === 'oled' ? 'bg-gray-800 border border-gray-700 hover:bg-gray-700' : 'bg-gray-200 dark:bg-gray-700 hover:bg-gray-300 dark:hover:bg-gray-600'} text-gray-600 dark:text-gray-300`
                    }`}
                    >
                    {board}
                    </button>
                ))}
               </div>
            </div>
          </div>
      </div>

      <div className="flex-grow overflow-y-auto py-6 px-4 space-y-6">
        {searchHistory.length === 0 && (
           <div className="flex flex-col items-center justify-center h-full text-gray-400 dark:text-gray-500 opacity-50 space-y-4">
             <svg className="w-16 h-16" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>
             <p className="text-lg italic font-light text-center">Ask a question to get a web-powered summary from Gemini.</p>
           </div>
        )}
        {searchHistory.map((msg, index) => (
          <div key={index} className={`flex ${msg.sender === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-2xl px-5 py-3 rounded-2xl shadow-md ${msg.sender === 'user' ? 'bg-indigo-600 text-white' : `${theme === 'oled' ? 'bg-black border border-gray-800' : 'bg-white dark:bg-gray-700'} text-gray-800 dark:text-gray-200`}`}>
              <div className="prose prose-gray dark:prose-invert max-w-none">
                <MarkdownRenderer content={msg.text} />
              </div>
              {msg.sources && msg.sources.length > 0 && (
                <div className={`mt-4 pt-3 border-t transition-colors duration-300 ${theme === 'oled' ? 'border-gray-800' : 'border-gray-200 dark:border-gray-600'}`}>
                  <h3 className="text-xs font-semibold text-gray-500 dark:text-gray-400 mb-2 flex items-center">
                      <svg className="w-4 h-4 mr-1.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13.828 10.172a4 4 0 00-5.656 0l-4 4a4 4 0 105.656 5.656l1.102-1.101m-.758-4.826L10.242 9.172a4 4 0 015.656 0l4 4a4 4 0 01-5.656 5.656l-1.102 1.101" /></svg>
                      Sources
                  </h3>
                  <div className="grid grid-cols-1 gap-2">
                    {msg.sources.map((source, idx) => (
                      <a
                        key={idx}
                        href={source.uri}
                        target="_blank"
                        rel="noopener noreferrer"
                        className={`block p-2 rounded-lg transition-colors duration-300 ${theme === 'oled' ? 'bg-gray-900 border border-gray-800 hover:bg-gray-800' : 'bg-gray-100 dark:bg-gray-800 hover:bg-gray-200 dark:hover:bg-gray-600'}`}
                      >
                        <p className="font-semibold text-indigo-700 dark:text-indigo-400 text-sm truncate">{source.title}</p>
                        <p className="text-xs text-gray-400 dark:text-gray-500 truncate">{source.uri}</p>
                      </a>
                    ))}
                  </div>
                </div>
              )}
            </div>
          </div>
        ))}

        {isLoading && (
            <div className="flex justify-start">
                <div className={`px-5 py-3 rounded-2xl shadow-md transition-colors duration-300 ${theme === 'oled' ? 'bg-black border border-gray-800' : 'bg-white dark:bg-gray-700'}`}>
                    <div className="flex items-center space-x-2">
                        <div className="w-2.5 h-2.5 bg-gray-400 rounded-full animate-pulse"></div>
                        <div className="w-2.5 h-2.5 bg-gray-400 rounded-full animate-pulse" style={{animationDelay: '0.2s'}}></div>
                        <div className="w-2.5 h-2.5 bg-gray-400 rounded-full animate-pulse" style={{animationDelay: '0.4s'}}></div>
                    </div>
                </div>
            </div>
        )}
        <div ref={messagesEndRef} />
      </div>

      <form onSubmit={handleSubmit} className={`p-4 border-t transition-colors duration-300 ${theme === 'oled' ? 'border-gray-800' : 'border-gray-200 dark:border-gray-700'}`}>
          <div className="flex items-center shadow-sm">
            <input
              type="text"
              value={query}
              onChange={(e) => setQuery(e.target.value)}
              placeholder="Ask a follow-up question or start a new search..."
              disabled={isLoading}
              className={`w-full text-gray-900 dark:text-white rounded-l-lg p-4 text-base focus:outline-none focus:ring-2 focus:ring-indigo-500 border border-transparent disabled:opacity-50 transition-colors duration-300 ${theme === 'oled' ? 'bg-gray-900 dark:border-gray-700' : 'bg-gray-200 dark:bg-gray-700 dark:border-gray-600'}`}
            />
            <button type="submit" disabled={isLoading} className="bg-indigo-600 text-white px-6 py-4 rounded-r-lg font-semibold hover:bg-indigo-700 transition-colors disabled:bg-gray-400 dark:disabled:bg-gray-500 flex items-center">
                <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 10l7-7m0 0l7 7m-7-7v18"></path></svg>
            </button>
          </div>
      </form>
    </div>
  );
}

import React, { useState } from 'react';
import { Theme } from '../types';

interface AuthPageProps {
  onLoginSuccess: () => void;
  onClose: () => void;
  theme: Theme;
}

export default function AuthPage({ onLoginSuccess, onClose, theme }: AuthPageProps) {
  const [isLogin, setIsLogin] = useState(true);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    // In a real app, you'd handle form data and API calls here.
    // For this simulation, we'll just log the user in.
    onLoginSuccess();
  };

  const isOLED = theme === 'oled';

  return (
    <div className="fixed inset-0 bg-black bg-opacity-75 flex items-center justify-center z-50 animate-fade-in">
      <div className={`relative w-full max-w-md p-8 space-y-6 rounded-xl shadow-lg transition-colors duration-300 ${isOLED ? 'bg-black border border-gray-800' : 'bg-white dark:bg-gray-800'}`}>
        <button onClick={onClose} className="absolute top-4 right-4 text-gray-500 hover:text-gray-800 dark:hover:text-gray-200">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12"></path></svg>
        </button>
        <div className="text-center">
          <div className="flex items-center justify-center mb-4">
            <img src="/logo.svg" alt="StudyLM Logo" className="w-10 h-10" />
            <div className="ml-2 text-left">
              <h1 className="text-3xl font-bold text-gray-900 dark:text-white">StudyLM</h1>
              <p className="text-sm text-gray-500 dark:text-gray-400 -mt-1">powered by Google Gemini</p>
            </div>
          </div>
          <p className="text-gray-500 dark:text-gray-400">
            {isLogin ? 'Log in to continue' : 'Create an account to continue'}
          </p>
        </div>

        <div className={`flex border-b transition-colors duration-300 ${isOLED ? 'border-gray-700' : 'border-gray-200 dark:border-gray-600'}`}>
          <button onClick={() => setIsLogin(true)} className={`w-1/2 py-4 text-center font-medium text-sm transition-colors ${isLogin ? 'border-b-2 border-indigo-500 text-indigo-600 dark:text-indigo-400' : 'text-gray-500 dark:text-gray-400 hover:text-gray-700 dark:hover:text-gray-200'}`}>
            Log In
          </button>
          <button onClick={() => setIsLogin(false)} className={`w-1/2 py-4 text-center font-medium text-sm transition-colors ${!isLogin ? 'border-b-2 border-indigo-500 text-indigo-600 dark:text-indigo-400' : 'text-gray-500 dark:text-gray-400 hover:text-gray-700 dark:hover:text-gray-200'}`}>
            Sign Up
          </button>
        </div>

        <form onSubmit={handleSubmit} className="space-y-6">
          <input
            type="email"
            placeholder="Email address"
            required
            className={`w-full px-4 py-3 text-gray-900 dark:text-white rounded-lg focus:outline-none focus:ring-2 focus:ring-indigo-500 transition-colors duration-300 ${isOLED ? 'bg-gray-900 border border-gray-700' : 'bg-gray-200 dark:bg-gray-700'}`}
          />
          <input
            type="password"
            placeholder="Password"
            required
            className={`w-full px-4 py-3 text-gray-900 dark:text-white rounded-lg focus:outline-none focus:ring-2 focus:ring-indigo-500 transition-colors duration-300 ${isOLED ? 'bg-gray-900 border border-gray-700' : 'bg-gray-200 dark:bg-gray-700'}`}
          />
          <button type="submit" className="w-full px-4 py-3 font-semibold text-white bg-indigo-600 rounded-lg hover:bg-indigo-700">
            {isLogin ? 'Log In' : 'Create Account'}
          </button>
        </form>

        <div className="relative flex items-center justify-center">
            <div className="absolute inset-0 flex items-center">
                <div className={`w-full border-t transition-colors duration-300 ${isOLED ? 'border-gray-700' : 'border-gray-300 dark:border-gray-600'}`}></div>
            </div>
            <div className={`relative px-2 text-sm text-gray-500 dark:text-gray-400 transition-colors duration-300 ${isOLED ? 'bg-black' : 'bg-white dark:bg-gray-800'}`}>Or continue with</div>
        </div>

        <button onClick={onLoginSuccess} className={`w-full flex items-center justify-center px-4 py-3 border rounded-lg transition-colors duration-300 ${isOLED ? 'border-gray-700 hover:bg-gray-900' : 'border-gray-300 dark:border-gray-600 hover:bg-gray-100 dark:hover:bg-gray-700'}`}>
            <GoogleIcon />
            <span className="ml-3 text-gray-700 dark:text-gray-200">Sign in with Google</span>
        </button>
      </div>
    </div>
  );
}

